type token = TIdent of string | TInt of int | TPct of int | TMinus | TLArrow | TRArrow | TLParen | TRParen | TLBrace | TRBrace | TComma | TUnderscore | THash of string | TLiteral of string | TUnknown of int | TEOF | TMint
let token_name t = match t with TIdent s -> "ident:" ^ s | TInt n -> "int:" ^ string_of_int n | TPct n -> "pct:" ^ string_of_int n | TMinus -> "minus" | TLArrow -> "larrow" | TRArrow -> "rarrow" | TLParen -> "lparen" | TRParen -> "rparen" | TLBrace -> "lbrace" | TRBrace -> "rbrace" | TComma -> "comma" | TUnderscore -> "slot" | THash s -> "comment:" ^ s | TLiteral s -> "lit:" ^ s | TUnknown n -> "unknown:" ^ string_of_int n | TEOF -> "eof" | TMint -> "mint"
let is_error_node n = match n with AError s -> true | _ -> false
let parse_statement toks = match toks with [] -> (AError "expected-token", []) | h :: t -> (match h with TEOF -> (AError "expected-token", toks) | THash _ -> (AError "expected-token", t) | TUnknown n -> (AError ("unknown-token:" ^ string_of_int n), t) | _ -> (AStmt [AAtom (token_name h)], t))
let rec skip_trivia toks = match toks with [] -> [] | h :: t -> (match h with THash _ -> skip_trivia t | _ -> toks)
let rec parse_program toks acc = let rest = skip_trivia toks in match rest with [] -> AProgram (List.rev acc) | h :: t -> (match h with TEOF -> AProgram (List.rev acc) | _ -> let pair = parse_statement rest in let node = fst pair in let after = snd pair in if is_error_node node then node else parse_program after (node :: acc))
let parse toks = parse_program toks []
